-- Seed source registry from planning pack register.
-- Safe to re-run.
ON CONFLICT (name, organization) DO UPDATE SET
    homepage_url = EXCLUDED.homepage_url,
    authority_level = EXCLUDED.authority_level,
    geographic_scope = EXCLUDED.geographic_scope,
    domain = EXCLUDED.domain,
    commercial_use_status = EXCLUDED.commercial_use_status,
    license_summary = EXCLUDED.license_summary,
    attribution_required = EXCLUDED.attribution_required,
    ai_use_allowed = EXCLUDED.ai_use_allowed,
    cache_allowed = EXCLUDED.cache_allowed,
    export_allowed = EXCLUDED.export_allowed,
    raw_data_allowed = EXCLUDED.raw_data_allowed,
    metadata = source.sources.metadata || EXCLUDED.metadata;
